import type { MenuContextType, MenuProviderProps } from ':components/Menu/Menu.types';
import React, { createContext, useContext, useMemo, useState } from 'react';

const MenuContext = createContext<MenuContextType | null>(null);

export const useMenuContext = (): MenuContextType => {
	const context = useContext(MenuContext);
	if (!context) {
		throw new Error('useMenuContext должен быть обернут в MenuProvider');
	}
	return context;
};

export const MenuProvider: React.FC<MenuProviderProps> = ({ children }) => {
	const [focusedId, setId] = useState<string>('');
	const [ids, setIds] = useState<string[]>([]);

	const setFocusedId = (id: string) => {
		setId(id);
	};

	const addId = (id: string) => {
		setIds([...ids, id]);
	};

	const value = useMemo(
		() => ({
			focusedId,
			setFocusedId,
			addId,
			ids,
		}),
		[ids, focusedId],
	);

	return <MenuContext.Provider value={value}>{children}</MenuContext.Provider>;
};
